const raw = $input.first().json;
const body = (raw.body !== undefined && typeof raw.body === 'object') ? raw.body : raw;
let payload;
if (body.payload !== undefined) {
  payload = typeof body.payload === 'string' ? JSON.parse(body.payload) : body.payload;
  if (!payload || typeof payload !== 'object') throw new Error('Parsed payload is not a valid object');
} else if (body.artifact !== undefined) {
  payload = { current: body.artifact, project: body.project || null, user: body.user || null, action: body.action || 'artifact:created' };
} else {
  throw new Error(`Unrecognized Tuleap webhook format. Body keys: ${Object.keys(body).join(', ')}`);
}
const tracker = payload.tracker || payload.current?.tracker;
if (!tracker?.id) throw new Error(`Missing tracker.id in payload. tracker = ${JSON.stringify(tracker)}`);
return [{ json: { payload } }];

const payload = $('Parse Payload').first().json.payload;
const configs = $('Fetch Sync Config').first().json.data || [];
const trackerId = payload?.tracker?.id;
const config = configs.find(c => String(c.tuleap_tracker_id) === String(trackerId));
if (!config) return [{ json: { hasConfig: false, trackerId, payload } }];
return [{ json: { hasConfig: true, config, payload } }];

const { config, payload } = $input.first().json;
const artifact = payload.current;
const fields = {};
for (const v of (artifact.values || [])) { fields[v.name] = v; }

function txt(...names) {
  for (const n of names) {
    const f = fields[n];
    if (f && f.value != null) return String(f.value);
  }
  return null;
}

function sel(...names) {
  for (const n of names) {
    const f = fields[n];
    if (f && f.values && f.values[0]) return f.values[0].label || f.values[0].display_name || null;
  }
  return null;
}

const artifactId = payload.id || artifact.id;

const tcData = {
  tuleap_artifact_id: artifactId,
  title: txt('title') || `Test Case ${artifactId}`,
  description: txt('test_steps'),
  priority: 'medium',
  category: 'other',
  status: 'active',
  project_id: config.qc_project_id,
  tags: [`tuleap:${artifactId}`],
  raw_tuleap_payload: payload
};

return [{ json: { tcData } }];
